import type { ScenarioQuestion } from "./types";

export const interviewPreparationClinical: ScenarioQuestion[] = [
  { id: "sq-ip-cj-1", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "You are assessing a post-operative patient and notice their heart rate has increased from 72 to 110, and their blood pressure has dropped from 130/80 to 95/60.", question: "What clinical actions would you take for this patient showing signs of possible internal bleeding?", exampleAnswer: "I would recognize these as potential signs of hemorrhage or hypovolemia. I would immediately assess the surgical site for signs of bleeding, check the drain output, and perform a focused assessment including skin color, temperature, and capillary refill. I would elevate the patient's legs, start or increase IV fluids if ordered, obtain a STAT hemoglobin and hematocrit, and notify the surgeon immediately with an SBAR report.", feedback: "Systematic assessment, early recognition of deterioration, and prompt physician notification.", starBreakdown: { situation: "Post-op patient showing tachycardia and hypotension 6 hours after abdominal surgery", task: "Assess for internal bleeding and intervene appropriately", action: "Checked surgical site, assessed drainage, elevated legs, started fluids, notified surgeon", result: "Patient returned to OR for surgical exploration, bleeding source identified and repaired" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-2", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient with diabetes tells you they feel shaky, sweaty, and confused. Their last blood glucose reading was 180 mg/dL taken 4 hours ago.", question: "How would you assess and manage a patient showing signs of hypoglycemia?", exampleAnswer: "I would immediately check a fingerstick blood glucose. While waiting for the result, I would assess the patient's level of consciousness and ability to swallow safely. If the glucose is low and the patient can swallow, I would provide 15g of fast-acting carbohydrates. If they cannot swallow safely, I would prepare to administer IV dextrose or glucagon. I would recheck the glucose in 15 minutes and notify the provider.", feedback: "Rapid assessment, appropriate intervention based on consciousness level, and follow-up monitoring.", starBreakdown: { situation: "Diabetic patient presenting with shakiness, diaphoresis, and confusion", task: "Quickly identify and treat hypoglycemia", action: "Checked blood glucose (found 45 mg/dL), gave orange juice, rechecked in 15 minutes", result: "Blood glucose rose to 120 mg/dL, symptoms resolved, provider adjusted insulin regimen" }, difficulty: "beginner" },
  { id: "sq-ip-cj-3", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "During morning assessment, you notice your patient with heart failure has gained 5 pounds overnight, has crackles in the lung bases, and their oxygen saturation has dropped to 89%.", question: "What does this clinical picture suggest and how would you respond?", exampleAnswer: "This presentation suggests fluid overload and worsening heart failure. I would elevate the head of the bed, apply supplemental oxygen to maintain SpO2 above 94%, assess for peripheral edema and jugular venous distension, and review recent intake and output records. I would notify the provider immediately, anticipate orders for a diuretic, and prepare for possible chest X-ray and BNP level.", feedback: "Recognition of heart failure exacerbation and appropriate nursing interventions.", starBreakdown: { situation: "Heart failure patient with sudden weight gain, crackles, and desaturation", task: "Recognize fluid overload and initiate appropriate interventions", action: "Elevated HOB, applied O2, assessed for edema, notified provider, prepared for diuretic", result: "Patient received IV Lasix, diuresed 2 liters, oxygen improved to 96%" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-4", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient on a heparin drip has their PTT come back at 120 seconds (therapeutic range 60-80 seconds).", question: "What actions would you take for a patient with a supratherapeutic PTT on heparin?", exampleAnswer: "I would recognize this as a critically elevated PTT indicating excessive anticoagulation. I would immediately stop the heparin infusion and notify the provider. I would assess the patient for signs of bleeding including checking IV sites, surgical wounds, urine, stool, and neurological status. I would anticipate orders for protamine sulfate if there is active bleeding and a repeat PTT in 4-6 hours.", feedback: "Immediate intervention to prevent bleeding complications and thorough bleeding assessment.", starBreakdown: { situation: "Heparin drip patient with PTT of 120, well above therapeutic range", task: "Prevent bleeding complications from excessive anticoagulation", action: "Stopped heparin, notified provider, assessed for bleeding, monitored vitals closely", result: "No active bleeding found, heparin restarted at lower rate, next PTT was therapeutic" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-5", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "You are caring for a patient who underwent a total knee replacement this morning. During your assessment, you notice the patient's calf is warm, red, and swollen.", question: "What clinical concern does this finding raise and what would you do?", exampleAnswer: "This presentation raises concern for deep vein thrombosis, which is a significant risk after joint replacement surgery. I would perform a thorough neurovascular assessment of the affected limb, avoid massaging the area, elevate the limb, and notify the surgeon immediately. I would anticipate orders for a Doppler ultrasound and possible anticoagulation therapy. I would also assess for signs of pulmonary embolism.", feedback: "Recognition of DVT signs, avoiding harmful interventions, and appropriate escalation.", starBreakdown: { situation: "Post-TKR patient with warm, red, swollen calf on operative side", task: "Assess for DVT and prevent complications", action: "Avoided massage, elevated limb, notified surgeon, prepared for Doppler ultrasound", result: "DVT confirmed, anticoagulation started promptly, no progression to PE" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-6", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient receiving a blood transfusion develops chills, back pain, and fever 15 minutes into the transfusion.", question: "What type of reaction do you suspect and what are your immediate actions?", exampleAnswer: "These symptoms suggest a possible hemolytic transfusion reaction, which is a medical emergency. I would immediately stop the transfusion while keeping the IV line open with normal saline. I would take vital signs and stay with the patient. I would notify the provider and blood bank immediately, send the blood bag and tubing to the lab for analysis, draw post-transfusion labs as ordered, and monitor urine output for hemoglobinuria.", feedback: "Immediate cessation of transfusion, maintaining IV access, and systematic notification.", starBreakdown: { situation: "Patient developed chills, fever, and back pain during blood transfusion", task: "Respond to possible transfusion reaction emergently", action: "Stopped transfusion, maintained IV, notified provider and blood bank, drew labs", result: "Reaction managed promptly, patient stabilized, investigation revealed clerical error" }, difficulty: "advanced" },
  { id: "sq-ip-cj-7", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "You are assessing a patient admitted for pneumonia and notice they are using accessory muscles to breathe, have nasal flaring, and are sitting in the tripod position.", question: "What does this clinical presentation indicate and what would you prioritize?", exampleAnswer: "These are signs of severe respiratory distress. My priorities would be to maintain the airway, assess oxygen saturation and apply high-flow oxygen immediately, perform a rapid respiratory assessment including lung sounds and respiratory rate, and call for help. I would position the patient for optimal breathing, prepare for possible intubation, and communicate the situation using SBAR to the provider.", feedback: "Recognition of respiratory distress severity and immediate airway/breathing interventions.", starBreakdown: { situation: "Pneumonia patient in tripod position with accessory muscle use and nasal flaring", task: "Address acute respiratory distress immediately", action: "Applied high-flow O2, assessed lungs, called rapid response, prepared for intubation", result: "Patient placed on BiPAP, ABG improved, avoided intubation with aggressive treatment" }, difficulty: "advanced" },
  { id: "sq-ip-cj-8", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient on telemetry shows a new-onset irregular rhythm. The monitor shows atrial fibrillation with a ventricular rate of 150 beats per minute.", question: "How would you respond to a patient with new-onset rapid atrial fibrillation?", exampleAnswer: "I would first assess the patient for hemodynamic stability—checking blood pressure, level of consciousness, and symptoms. I would obtain a 12-lead ECG to confirm the rhythm, notify the provider immediately, and prepare for possible cardioversion or rate control medications. I would establish IV access if not already present, monitor the patient continuously, and assess for underlying causes like electrolyte imbalances or infection.", feedback: "Hemodynamic assessment first, then rhythm confirmation and provider notification.", starBreakdown: { situation: "Telemetry alarm showing new rapid atrial fibrillation at 150 bpm", task: "Assess stability and facilitate appropriate treatment", action: "Assessed hemodynamic status, obtained 12-lead ECG, notified provider, prepared for treatment", result: "Patient received IV diltiazem, heart rate controlled to 85 bpm, cardiology consulted" }, difficulty: "advanced" },
  { id: "sq-ip-cj-9", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "During a medication pass, you notice that a patient's potassium level is 6.2 mEq/L, and they are ordered for a potassium supplement.", question: "What would you do with this critical lab value and medication order conflict?", exampleAnswer: "I would hold the potassium supplement immediately, as administering it with an already dangerously elevated level could cause fatal cardiac arrhythmia. I would notify the provider of the critical lab value, assess the patient for signs of hyperkalemia including muscle weakness and ECG changes, and anticipate orders for cardiac monitoring, calcium gluconate, insulin and glucose, or sodium polystyrene sulfonate.", feedback: "Recognizing dangerous lab-medication interactions and holding inappropriate medications.", starBreakdown: { situation: "Patient's potassium at 6.2 with an active order for potassium supplementation", task: "Prevent harm from contraindicated medication", action: "Held potassium, notified provider, placed on cardiac monitor, assessed for symptoms", result: "Provider ordered IV calcium and insulin-glucose protocol, potassium normalized" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-10", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient with COPD is on 2L nasal cannula oxygen. A well-meaning family member turns the oxygen up to 6L.", question: "Why is this dangerous and what would you do?", exampleAnswer: "In COPD patients, high-flow oxygen can suppress their hypoxic drive, which is their primary stimulus for breathing. This could lead to respiratory depression or arrest. I would immediately reduce the oxygen back to the prescribed rate, assess the patient's respiratory status and level of consciousness, check oxygen saturation, and educate the family member about why the prescribed rate is important and why they should not adjust medical equipment.", feedback: "Understanding of COPD pathophysiology and the importance of controlled oxygen therapy.", starBreakdown: { situation: "Family member increased COPD patient's O2 from 2L to 6L nasal cannula", task: "Prevent respiratory depression from excessive oxygenation", action: "Reduced O2 to prescribed rate, assessed respiratory status, educated family", result: "Patient maintained stable respiratory status, family understood the importance of prescribed settings" }, difficulty: "beginner" },
  { id: "sq-ip-cj-11", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "You are caring for a postpartum patient and notice excessive vaginal bleeding, a boggy uterus, and the patient reports feeling dizzy.", question: "What is your assessment and immediate nursing response?", exampleAnswer: "This presentation indicates postpartum hemorrhage, likely due to uterine atony. I would immediately perform uterine massage to stimulate contraction, monitor vital signs frequently, start or increase IV fluids, and call for help. I would weigh pads to quantify blood loss, prepare for oxytocin administration, and notify the provider urgently. I would also keep the patient warm and assess for signs of shock.", feedback: "Rapid identification of postpartum hemorrhage and appropriate emergent interventions.", starBreakdown: { situation: "Postpartum patient with excessive bleeding, boggy uterus, and dizziness", task: "Intervene emergently for suspected postpartum hemorrhage", action: "Started uterine massage, increased IV fluids, called provider, prepared oxytocin", result: "Uterus firmed with massage and oxytocin, bleeding controlled, patient stabilized" }, difficulty: "advanced" },
  { id: "sq-ip-cj-12", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient scheduled for surgery in 2 hours tells you they ate breakfast this morning against the NPO instructions.", question: "How would you handle a patient who violated NPO status before surgery?", exampleAnswer: "I would immediately notify the surgical team and anesthesiologist. Eating before surgery significantly increases aspiration risk during anesthesia. I would document exactly what and when the patient ate. The surgical team would decide whether to proceed, delay, or cancel the surgery. I would educate the patient about the importance of NPO status and the risks of aspiration.", feedback: "Immediate notification of surgical team and understanding of aspiration risk.", starBreakdown: { situation: "Surgical patient consumed a full breakfast 2 hours before scheduled procedure", task: "Communicate the NPO violation to prevent aspiration risk", action: "Notified surgeon and anesthesiologist immediately, documented intake details", result: "Surgery delayed 6 hours, patient educated, procedure completed safely later" }, difficulty: "beginner" },
  { id: "sq-ip-cj-13", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient with a chest tube suddenly develops subcutaneous emphysema around the insertion site, and their oxygen saturation drops.", question: "What does subcutaneous emphysema near a chest tube suggest?", exampleAnswer: "Subcutaneous emphysema near a chest tube site could indicate a displaced or occluded tube, a new air leak, or worsening pneumothorax. I would assess the chest tube system for proper functioning—checking for bubbling, fluctuation, and kinks. I would assess the patient's respiratory status, vital signs, and breath sounds. I would notify the provider immediately and prepare for a chest X-ray. I would never clamp the chest tube without a physician order.", feedback: "Systematic assessment of chest tube function and recognition of potential complications.", starBreakdown: { situation: "Chest tube patient developed crepitus around insertion site with dropping O2", task: "Assess for chest tube malfunction and respiratory compromise", action: "Checked tube system, assessed respiratory status, notified provider, prepared for imaging", result: "Chest X-ray showed tube displacement, tube repositioned, patient's O2 improved" }, difficulty: "advanced" },
  { id: "sq-ip-cj-14", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "You are caring for a stroke patient and during assessment notice their speech has become slurred and they have new facial drooping on the left side.", question: "How would you assess and respond to new neurological changes in a stroke patient?", exampleAnswer: "I would recognize these as signs of a possible new or extending stroke. I would perform a rapid neurological assessment using the NIH Stroke Scale, note the exact time symptoms were first observed, keep the patient NPO in case of swallowing impairment, and activate the stroke code protocol immediately. I would ensure IV access and prepare for an emergent CT scan.", feedback: "Time-sensitive recognition of stroke symptoms and activation of stroke protocol.", starBreakdown: { situation: "Admitted stroke patient developing new slurred speech and left facial droop", task: "Recognize stroke progression and activate emergency protocol", action: "Performed NIH Stroke Scale, noted time, activated stroke code, prepared for CT", result: "CT showed clot extension, tPA administered within window, deficits partially resolved" }, difficulty: "advanced" },
  { id: "sq-ip-cj-15", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient on a ventilator starts fighting the ventilator, and the high-pressure alarm is sounding repeatedly.", question: "What are the possible causes and how would you troubleshoot?", exampleAnswer: "High-pressure alarms on a ventilator can be caused by patient-ventilator dyssynchrony, secretions in the airway, bronchospasm, biting the ET tube, pneumothorax, or kinked tubing. I would assess the patient first, then the equipment. I would suction the airway, check tube position and for kinking, auscultate lung sounds, and assess for signs of pneumothorax. If the issue persisted, I would bag the patient manually and notify the provider.", feedback: "Patient-first assessment approach and systematic troubleshooting of ventilator alarms.", starBreakdown: { situation: "Ventilated patient fighting the vent with repeated high-pressure alarms", task: "Identify and resolve the cause of patient-ventilator dyssynchrony", action: "Assessed patient, suctioned thick secretions, repositioned ET tube, checked lung sounds", result: "Thick mucus plug cleared, pressures normalized, respiratory comfort restored" }, difficulty: "advanced" },
  { id: "sq-ip-cj-16", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient receiving IV vancomycin develops a widespread red rash across their face, neck, and upper torso within 10 minutes of starting the infusion.", question: "What is this likely reaction and how would you manage it?", exampleAnswer: "This is likely Red Man Syndrome, a histamine-mediated reaction to rapid vancomycin infusion. I would slow or stop the infusion, take vital signs, and assess the severity of the reaction. I would notify the provider and anticipate an order for diphenhydramine. Unlike true anaphylaxis, Red Man Syndrome is usually managed by slowing the infusion rate. I would monitor for signs of true allergy and document the reaction.", feedback: "Distinction between Red Man Syndrome and anaphylaxis, appropriate rate adjustment.", starBreakdown: { situation: "Patient developed red flushing of face and chest during vancomycin infusion", task: "Identify Red Man Syndrome and manage appropriately", action: "Stopped infusion, assessed vitals, gave Benadryl per order, restarted at slower rate", result: "Rash resolved, vancomycin infused over 2 hours without further reaction" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-17", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "You are caring for a pediatric patient and notice their fontanelle is bulging and they are inconsolable with high-pitched crying.", question: "What does a bulging fontanelle indicate in an infant?", exampleAnswer: "A bulging fontanelle in an infant suggests increased intracranial pressure, which could indicate meningitis, encephalitis, hydrocephalus, or intracranial hemorrhage. Combined with high-pitched crying, this is concerning for a serious neurological condition. I would assess vital signs including temperature, perform a neurological assessment, keep the infant with head elevated, and notify the provider immediately as this requires emergent evaluation.", feedback: "Recognition of increased ICP in pediatric patients and appropriate emergency response.", starBreakdown: { situation: "6-month-old with bulging fontanelle, high-pitched cry, and temperature of 39.5C", task: "Recognize signs of possible meningitis and respond emergently", action: "Assessed neurological status, notified provider, prepared for lumbar puncture and IV antibiotics", result: "Bacterial meningitis diagnosed, IV antibiotics started promptly, child recovered fully" }, difficulty: "advanced" },
  { id: "sq-ip-cj-18", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient on a PCA pump is difficult to arouse and their respiratory rate is 8 breaths per minute.", question: "What would you do for a patient showing signs of opioid oversedation?", exampleAnswer: "I would recognize these as signs of opioid-induced respiratory depression. I would immediately stop the PCA pump, stimulate the patient, call for help, and prepare to administer naloxone (Narcan). I would apply supplemental oxygen, position the patient to maintain airway patency, and monitor vital signs continuously. I would notify the provider and document the event.", feedback: "Immediate recognition of opioid toxicity and life-saving intervention.", starBreakdown: { situation: "Post-surgical patient on PCA pump barely arousable with respiratory rate of 8", task: "Reverse opioid-induced respiratory depression", action: "Stopped PCA, stimulated patient, applied O2, gave Narcan per protocol, notified provider", result: "Patient's respiratory rate improved to 16, pain management plan adjusted" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-19", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient admitted for cellulitis on IV antibiotics develops a temperature of 38.8C, and you notice a new area of redness spreading up the arm with red streaking.", question: "What does this clinical finding suggest?", exampleAnswer: "Red streaking extending from the infection site suggests lymphangitis, indicating the infection is spreading to the lymphatic system. This could progress to sepsis. I would mark the borders of the redness with a time stamp to track progression, obtain blood cultures before any antibiotic changes, take a complete set of vital signs, and notify the provider immediately. I would assess for signs of sepsis including altered mental status.", feedback: "Tracking infection progression and recognizing the risk of systemic spread.", starBreakdown: { situation: "Cellulitis patient developing lymphangitis with red streaking despite current antibiotics", task: "Identify worsening infection and escalate care", action: "Marked redness borders, drew blood cultures, assessed for sepsis, notified provider", result: "Antibiotics upgraded to broader spectrum, infection progression halted" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-20", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "clinical_judgment", scenarioPrompt: "A patient with a history of seizures begins having tonic-clonic movements while in bed.", question: "What are your immediate nursing actions during a seizure?", exampleAnswer: "I would prioritize safety: lower the bed, raise the side rails with padding if available, move nearby objects, and position the patient on their side to prevent aspiration. I would note the time the seizure started, observe the type and pattern of movements, and monitor airway and breathing. I would NOT put anything in the patient's mouth. I would call for help, prepare for possible medication administration, and time the seizure for status epilepticus threshold.", feedback: "Safety-focused interventions, airway protection, and seizure monitoring.", starBreakdown: { situation: "Known epileptic patient experiencing tonic-clonic seizure in bed", task: "Ensure patient safety during active seizure", action: "Lowered bed, padded rails, turned to side, timed seizure, called for help", result: "Seizure resolved in 2 minutes, patient assessed post-ictally, medications adjusted" }, difficulty: "beginner" },
  { id: "sq-ip-cj-21", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "scenario_responses", scenarioPrompt: "A patient asks you to explain what their new diagnosis of Type 2 diabetes means for their daily life.", question: "How would you approach patient education for a new diabetes diagnosis?", exampleAnswer: "I would assess the patient's current understanding and emotional readiness to learn. I would explain diabetes in simple, non-medical terms, focusing on what they can control. I would cover the basics: blood sugar monitoring, dietary changes, medication importance, exercise, and recognizing hypo/hyperglycemia symptoms. I would use teach-back method to verify understanding and provide written materials for reference.", feedback: "Patient-centered education with assessment of readiness and use of teach-back.", starBreakdown: { situation: "Newly diagnosed Type 2 diabetic overwhelmed by the diagnosis", task: "Provide effective, compassionate diabetes education", action: "Assessed readiness, used simple language, covered essentials, used teach-back method", result: "Patient demonstrated understanding of glucose monitoring and medication schedule" }, difficulty: "beginner" },
  { id: "sq-ip-cj-22", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "scenario_responses", scenarioPrompt: "You are caring for a patient who has just been told their cancer is terminal. They look at you and ask, 'Am I going to die?'", question: "How would you respond to a terminally ill patient asking if they are going to die?", exampleAnswer: "I would sit down and give the patient my full attention. I would respond honestly and compassionately: 'Your doctor has shared that your illness is very serious. I want you to know that I am here for you, and our team is focused on making sure you are comfortable and cared for.' I would listen to their fears and concerns, offer to involve the palliative care team or chaplain, and ensure they know they are not alone.", feedback: "Honesty with compassion, presence, and offering additional support resources.", starBreakdown: { situation: "Terminal cancer patient directly asked about their prognosis", task: "Provide honest, compassionate response while offering support", action: "Sat with patient, acknowledged the gravity, offered presence and resources", result: "Patient expressed fears, palliative care consulted, family meeting arranged" }, difficulty: "advanced" },
  { id: "sq-ip-cj-23", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "scenario_responses", scenarioPrompt: "A patient refuses to take their medications because they believe they are not helping and are causing side effects.", question: "How would you handle medication refusal by an informed patient?", exampleAnswer: "I would listen to the patient's concerns about the medications and take them seriously. I would explain the purpose of each medication and the risks of not taking them. I would ask about specific side effects they are experiencing and relay these to the provider. I would document the refusal and the education provided. Ultimately, I would respect the patient's right to refuse while ensuring they have all the information to make an informed decision.", feedback: "Patient education, side effect assessment, and respect for patient autonomy.", starBreakdown: { situation: "Cardiac patient refusing beta-blocker due to fatigue and dizziness", task: "Address concerns while ensuring informed medication refusal", action: "Listened to side effects, educated on medication purpose, relayed concerns to provider", result: "Provider adjusted medication to a different beta-blocker with fewer side effects" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-24", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "scenario_responses", scenarioPrompt: "You are doing discharge teaching and realize the patient does not understand their medication schedule because they have low literacy.", question: "How would you modify discharge education for a patient with limited literacy?", exampleAnswer: "I would use visual aids, pictures, and color-coding rather than written instructions alone. I would demonstrate medication administration and have the patient practice. I would use simple language and avoid medical jargon. I would involve a family member or caregiver in the teaching if the patient consents. I would follow up with phone calls after discharge and arrange for pharmacy consultation.", feedback: "Recognizing literacy barriers and adapting education methods appropriately.", starBreakdown: { situation: "Elderly patient unable to read discharge medication instructions", task: "Ensure safe medication self-administration despite literacy limitations", action: "Used picture-based medication schedule, color-coded pills, taught family member", result: "Patient and family demonstrated correct medication administration before discharge" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-25", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "scenario_responses", scenarioPrompt: "A patient scheduled for a procedure tells you they are very anxious and asks if they can refuse the procedure.", question: "How would you support an anxious patient who is considering refusing a procedure?", exampleAnswer: "I would validate their anxiety and assure them that it is completely normal to feel nervous. I would explore what specifically is causing their anxiety—is it the procedure itself, the anesthesia, or the potential results? I would provide information about what to expect and answer their questions. I would affirm their right to refuse while ensuring they understand the implications. I would offer comfort measures and suggest speaking with the physician for additional reassurance.", feedback: "Validation, exploration of specific fears, and informed consent support.", starBreakdown: { situation: "Patient extremely anxious about cardiac catheterization, considering refusal", task: "Support the patient's emotional needs while ensuring informed decision-making", action: "Validated fears, answered specific questions, offered to call physician for discussion", result: "Patient's specific fear addressed, proceeded with procedure, had a successful outcome" }, difficulty: "beginner" },
  { id: "sq-ip-cj-26", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "star_examples", scenarioPrompt: "Tell me about a time in clinical when you went above and beyond for a patient.", question: "Describe a situation where you exceeded expectations in patient care.", exampleAnswer: "During my clinical rotation, I was caring for an elderly patient who had been hospitalized for two weeks and was showing signs of depression. I noticed she had not had any visitors and her meals were often left untouched. Beyond my regular nursing duties, I spent extra time with her during my breaks, helped her call her grandchildren, and coordinated with the dietitian to provide meals she actually enjoyed. I also arranged for a volunteer to visit her regularly after I noticed the improvement in her mood.", feedback: "Shows initiative, holistic care, and resourcefulness beyond basic requirements.", starBreakdown: { situation: "Elderly patient hospitalized for 2 weeks with no visitors, showing signs of depression", task: "Address psychosocial needs beyond basic medical care", action: "Spent extra time, facilitated family contact, coordinated dietary changes, arranged volunteer visits", result: "Patient's mood improved significantly, started eating better, engaged more in recovery" }, difficulty: "beginner" },
  { id: "sq-ip-cj-27", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "star_examples", scenarioPrompt: "Describe a time you had to adapt quickly to an unexpected change during clinical.", question: "How did you handle an unexpected situation during clinical training?", exampleAnswer: "During my medical-surgical rotation, I was assigned to a stable patient who suddenly developed chest pain and became diaphoretic. Although I had not yet experienced an acute cardiac event, I immediately assessed the patient, called for help, obtained vital signs, and helped the RN administer nitroglycerin and connect the 12-lead ECG. I stayed calm, followed the emergency protocol I had studied, and assisted until the patient was stabilized and transferred to the cardiac care unit.", feedback: "Demonstrates composure under pressure, application of theoretical knowledge, and teamwork.", starBreakdown: { situation: "Stable med-surg patient suddenly developed chest pain and diaphoresis", task: "Respond to unexpected cardiac emergency during clinical rotation", action: "Assessed immediately, called for help, took vitals, assisted with ECG and medications", result: "Patient stabilized and transferred to cardiac care, instructor commended my response" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-28", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "star_examples", scenarioPrompt: "Tell me about a time you had to work with a team member who had a very different work style than yours.", question: "How did you collaborate effectively with someone whose approach differed from yours?", exampleAnswer: "During my final clinical practicum, I was paired with a preceptor who had a very fast-paced, minimal-explanation style. I prefer detailed instruction before attempting new skills. Rather than becoming frustrated, I adapted by preparing extensively before each shift—reviewing procedures, medications, and patient conditions. I asked specific questions at appropriate times rather than expecting lengthy explanations. By the end, we developed an efficient partnership that combined her experience with my thorough preparation.", feedback: "Adaptability, self-awareness, and proactive communication style adjustment.", starBreakdown: { situation: "Preceptor had a fast-paced teaching style that conflicted with my detailed learning preference", task: "Adapt to work effectively despite different approaches", action: "Pre-studied before shifts, asked targeted questions, adapted communication style", result: "Developed efficient partnership, preceptor gave excellent evaluation, learned self-adaptation skills" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-29", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "common_nursing_interview", scenarioPrompt: "The interviewer asks you: 'Why did you choose nursing as a career?'", question: "Why did you choose nursing?", exampleAnswer: "I chose nursing because I wanted a career that combines scientific knowledge with meaningful human connection. During a family member's hospitalization, I witnessed how nurses made the most significant difference in the patient experience—not just through clinical skills, but through compassion and advocacy. I realized I wanted to be that person for others. Nursing offers the unique ability to impact lives during some of the most vulnerable moments, and the diversity of career paths within nursing means I can continue growing throughout my career.", feedback: "Authentic motivation, personal connection, and awareness of the profession's scope.", starBreakdown: { situation: "Reflecting on what drew me to the nursing profession", task: "Articulate a genuine and compelling reason for choosing nursing", action: "Connected personal experience with professional calling, highlighted key values", result: "Demonstrated authentic passion and understanding of what nursing truly entails" }, difficulty: "beginner" },
  { id: "sq-ip-cj-30", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "common_nursing_interview", scenarioPrompt: "The interviewer asks: 'What is your greatest weakness as a nurse?'", question: "What is your greatest weakness?", exampleAnswer: "My greatest weakness has been wanting to do everything perfectly, which sometimes slowed down my efficiency in clinical. I recognized that perfectionism was actually holding me back from developing confidence in my time management. To address this, I started using a structured priority system during each shift and set realistic time limits for tasks. I have learned that 'good enough and safe' is better than 'perfect but late,' and my efficiency has improved significantly while maintaining quality care.", feedback: "Honest self-assessment with a clear growth strategy—avoid cliche answers.", starBreakdown: { situation: "Perfectionism affecting clinical efficiency during nursing rotations", task: "Address the weakness with a concrete improvement plan", action: "Implemented priority system, set time limits, focused on efficiency without sacrificing safety", result: "Improved efficiency by 30%, maintained quality, preceptor noted significant growth" }, difficulty: "beginner" },
  { id: "sq-ip-cj-31", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "common_nursing_interview", scenarioPrompt: "The interviewer asks: 'Where do you see yourself in five years?'", question: "Where do you see yourself in five years?", exampleAnswer: "In five years, I see myself as a confident, competent nurse with a strong clinical foundation. I plan to spend my first two years building strong bedside skills on this unit. By year three, I hope to pursue a specialty certification and potentially take on a charge nurse role. Long-term, I am interested in clinical education or pursuing advanced practice. I am committed to this facility because of its reputation for professional development and mentorship.", feedback: "Shows ambition while demonstrating commitment to the facility and realistic progression.", starBreakdown: { situation: "Planning long-term career trajectory as a new graduate", task: "Articulate a realistic and facility-aligned career vision", action: "Outlined progressive goals from bedside competency to leadership or advanced practice", result: "Demonstrated ambition, loyalty to the facility, and realistic self-awareness" }, difficulty: "beginner" },
  { id: "sq-ip-cj-32", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "common_nursing_interview", scenarioPrompt: "The interviewer asks: 'Why should we hire you over other candidates?'", question: "Why should we hire you?", exampleAnswer: "You should hire me because I bring a combination of strong clinical preparation, genuine compassion, and a growth mindset. I have actively sought out challenging clinical experiences during my training, maintained excellent academic performance, and I am genuinely excited about working in this specific unit. I am not just looking for a job—I am looking for a professional home where I can grow and contribute. My willingness to learn, accept feedback, and go above and beyond makes me a strong investment for your team.", feedback: "Confidence without arrogance, specificity about strengths, and genuine enthusiasm.", starBreakdown: { situation: "Competing with many qualified candidates for a desirable position", task: "Differentiate myself authentically from other applicants", action: "Highlighted unique qualities, clinical experiences, and genuine enthusiasm for the unit", result: "Demonstrated value proposition beyond basic qualifications" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-33", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "difficult_interviewer", scenarioPrompt: "The interviewer seems cold, uninterested, and keeps checking their phone during your interview.", question: "How would you respond to a disengaged interviewer?", exampleAnswer: "I would maintain my professionalism and enthusiasm regardless of the interviewer's behavior. I would continue to give thoughtful, complete answers and make eye contact. I would not take their behavior personally—they may be dealing with unit emergencies or testing my resilience under stress. I might gently re-engage by asking a question about their experience on the unit or what they enjoy most about working there.", feedback: "Resilience, not taking it personally, and attempt to engage.", starBreakdown: { situation: "Interviewer appeared distracted and uninterested throughout the interview", task: "Maintain composure and deliver a strong interview despite the environment", action: "Stayed professional, gave thorough answers, asked engaging questions about the unit", result: "Interviewer later explained they were testing stress response, offered the position" }, difficulty: "advanced" },
  { id: "sq-ip-cj-34", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "difficult_interviewer", scenarioPrompt: "The interviewer asks: 'You have no experience. Why should I take a risk on you?'", question: "How would you respond to an interviewer questioning your lack of experience?", exampleAnswer: "I would acknowledge the concern directly and reframe my position: 'You are right that I am new to professional nursing, but I bring current evidence-based knowledge, clinical hours across diverse settings, and a fresh perspective unclouded by outdated habits. New graduates are coachable, enthusiastic, and eager to learn your way of doing things. My clinical evaluations consistently praised my critical thinking and ability to learn quickly. I am a low-risk investment because I will work harder than anyone to prove myself.'", feedback: "Acknowledging the concern, reframing experience as an asset, and showing confidence.", starBreakdown: { situation: "Interviewer directly challenged my lack of professional experience", task: "Address the concern confidently without being defensive", action: "Acknowledged the gap, highlighted strengths of new graduates, cited clinical evaluations", result: "Reframed inexperience as an asset—coachability, current knowledge, enthusiasm" }, difficulty: "advanced" },
  { id: "sq-ip-cj-35", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "difficult_interviewer", scenarioPrompt: "The interviewer asks a rapid series of clinical questions to test your knowledge under pressure.", question: "How would you handle being rapid-fire quizzed during an interview?", exampleAnswer: "I would take a brief pause before each answer to collect my thoughts rather than rushing into responses. If I knew the answer, I would respond clearly and concisely. If I was unsure, I would say, 'I would want to verify this by checking a reference, but based on my understanding...' I would not pretend to know something I did not. Demonstrating a safe, thoughtful approach is more important than answering every question perfectly.", feedback: "Honest knowledge boundaries and safe clinical thinking under pressure.", starBreakdown: { situation: "Interviewer asked rapid clinical questions testing pharmacology and assessment knowledge", task: "Demonstrate clinical knowledge while maintaining composure", action: "Paused briefly before answers, admitted uncertainty when appropriate, showed clinical reasoning", result: "Interviewer noted that my honest approach to uncertain answers was the best response" }, difficulty: "advanced" },
  { id: "sq-ip-cj-36", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "panel_interview", scenarioPrompt: "You are interviewing before a panel of four people: the nurse manager, a charge nurse, a staff nurse, and an HR representative.", question: "How would you manage a panel interview with multiple interviewers?", exampleAnswer: "I would make eye contact with each panel member when answering questions, directing my primary response to the person who asked the question while including the others. I would note each person's name and role at the beginning. I would tailor parts of my answers to resonate with different roles—clinical examples for the nurses, organizational fit for HR. I would ask each panel member a question at the end to show genuine interest in their perspective.", feedback: "Inclusive engagement with all panel members and role-appropriate communication.", starBreakdown: { situation: "Panel interview with nurse manager, charge nurse, staff nurse, and HR representative", task: "Engage effectively with multiple interviewers simultaneously", action: "Made eye contact with all, noted names, tailored answers, asked each a question", result: "All panel members felt engaged, received positive feedback on interpersonal skills" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-37", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "panel_interview", scenarioPrompt: "During a panel interview, two panel members seem to disagree about the best answer to a scenario question.", question: "How would you respond when panel members seem to have different perspectives?", exampleAnswer: "I would acknowledge both viewpoints respectfully and demonstrate that I understand there can be multiple valid approaches to clinical situations. I might say, 'I can see how both approaches have merit, and I think the best approach might depend on the specific circumstances.' This shows flexibility and the ability to consider multiple perspectives rather than choosing sides.", feedback: "Diplomatic handling of differing opinions and demonstrating clinical flexibility.", starBreakdown: { situation: "Two panel members disagreed about prioritization in a scenario question", task: "Navigate the disagreement without alienating either interviewer", action: "Acknowledged both perspectives, explained how context might determine the best approach", result: "Both interviewers nodded in agreement, appreciated the nuanced response" }, difficulty: "advanced" },
  { id: "sq-ip-cj-38", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "scenario_responses", scenarioPrompt: "A patient you discharged yesterday is readmitted with complications. You wonder if you missed something during discharge.", question: "How would you handle learning that a recently discharged patient was readmitted?", exampleAnswer: "I would review my discharge documentation carefully to assess whether all appropriate teaching, follow-up instructions, and safety assessments were completed. I would not immediately assume blame, but I would objectively evaluate if I could have done something differently. If I identified a gap, I would discuss it with my manager as a learning opportunity. If the readmission was unavoidable, I would use it to reinforce the importance of thorough discharge planning.", feedback: "Self-reflection without excessive self-blame, and commitment to learning.", starBreakdown: { situation: "Heart failure patient I discharged returned within 24 hours with fluid overload", task: "Evaluate my discharge process and identify improvement opportunities", action: "Reviewed documentation, identified that dietary education could have been more thorough, discussed with manager", result: "Developed a more comprehensive discharge checklist for heart failure patients" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-39", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "scenario_responses", scenarioPrompt: "You are asked to admit a patient to a shared room, but the patient in the room already has a known MRSA infection.", question: "What infection control considerations would guide your decision?", exampleAnswer: "I would raise this concern with the charge nurse immediately. Placing a patient in a room with a known MRSA-positive patient could put the new patient at risk for healthcare-associated infection. I would advocate for proper isolation precautions and an alternative room placement if possible. If placement must occur, I would ensure proper contact precautions, hand hygiene, and dedicated equipment for each patient.", feedback: "Infection control knowledge and patient advocacy regarding safe room assignments.", starBreakdown: { situation: "New admission being placed in a shared room with MRSA-positive patient", task: "Advocate for appropriate infection control measures", action: "Raised concern with charge nurse, advocated for alternative placement, ensured precautions", result: "Patient placed in a different room, infection control protocols maintained" }, difficulty: "intermediate" },
  { id: "sq-ip-cj-40", formatType: "scenario", categoryGroup: "interview_preparation", subcategory: "scenario_responses", scenarioPrompt: "A patient's family member asks you not to tell the patient about their diagnosis because they believe the patient cannot handle the news.", question: "How would you handle a family's request to withhold information from a patient?", exampleAnswer: "I would acknowledge the family's concern and their desire to protect their loved one. However, I would explain that patients have a right to know their diagnosis and that withholding information can undermine trust and their ability to make informed decisions. I would offer to help facilitate the conversation with the physician present and provide emotional support for both the patient and family. Cultural considerations would also be explored.", feedback: "Balancing family concerns with patient's right to information and informed consent.", starBreakdown: { situation: "Family asked nurses not to tell elderly father about his cancer diagnosis", task: "Respect the family's concerns while upholding patient's right to know", action: "Acknowledged concern, explained patient rights, facilitated a family conference with physician", result: "Patient was informed with family and physician support, felt empowered in care decisions" }, difficulty: "advanced" },
];
